import{_ as e,c as a,ag as i,o as s}from"./chunks/framework.mHuDn-wg.js";const h="/assets/shell.REWBkdcF.png",_=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"计算机/计算机语言/概述.md","filePath":"计算机/计算机语言/概述.md","lastUpdated":null}'),o={name:"计算机/计算机语言/概述.md"};function t(r,l,n,d,c,u){return s(),a("div",null,l[0]||(l[0]=[i('<p>编程的范式</p><h2 id="为什么要懂一点编程" tabindex="-1">为什么要懂一点编程 <a class="header-anchor" href="#为什么要懂一点编程" aria-label="Permalink to &quot;为什么要懂一点编程&quot;">​</a></h2><h2 id="分类" tabindex="-1">分类 <a class="header-anchor" href="#分类" aria-label="Permalink to &quot;分类&quot;">​</a></h2><p>根据代码如何执行, 可以分为两大类 1. 解释型语言，解释器解释执行 2. 编译型语言，编译成机器语言后执行</p><p>其他分类</p><ul><li>系统编程语言: C, C++</li><li>应用编程语言: Java, C#</li><li>脚本语言，编程语言的子集，属于解释型语言: python, javascript, shell</li><li>web开发语言: html, css, php</li><li>科学计算数据分析: R, MATLAB, python</li><li>...</li></ul><h2 id="shell" tabindex="-1">shell <a class="header-anchor" href="#shell" aria-label="Permalink to &quot;shell&quot;">​</a></h2><ul><li>shell 是计算机操作系统的用户界面, 是用户与内核交互的接口</li><li>shell 是一个命令解释器,</li><li><img src="'+h+'" alt="shell的结构"></li><li>分为：①命令行界面（CLI）；② 图形用户界面（GUI）</li><li>例如: macos的finder, linux的窗口管理器, windows的explorer和dos shell都属于GUI式的shell</li><li>无特殊说明一般指命令行界面shell</li></ul><h3 id="windows的shell" tabindex="-1">windows的shell <a class="header-anchor" href="#windows的shell" aria-label="Permalink to &quot;windows的shell&quot;">​</a></h3><ul><li>CMD: command prompt</li><li>powershell</li><li>WSL</li></ul><h3 id="linux的shell" tabindex="-1">linux的shell <a class="header-anchor" href="#linux的shell" aria-label="Permalink to &quot;linux的shell&quot;">​</a></h3><ul><li>sh: 最早的unix shell</li><li>bash: 最常用的linux shell</li><li>fish, zsh 等是一些现代的shell, 用户友好, 补全功能更智能.</li><li><a href="https://blog.csdn.net/qq_33154343/article/details/123366377" target="_blank" rel="noreferrer">Shell、Bash、CMD、PowerShell 的区别_powershell bash-CSDN博客</a></li></ul><h3 id="shell编程" tabindex="-1">shell编程 <a class="header-anchor" href="#shell编程" aria-label="Permalink to &quot;shell编程&quot;">​</a></h3><p>shell 提供了一种脚本语言, 组合多个命令, 实现复杂逻辑和自动化操作, 甚至编写一些简单的应用. 例如:</p><ul><li>windows cmd的批处理文件<code>.bat</code></li><li>windows powershell的脚本文件<code>.ps1</code></li><li>linux 的脚本文件<code>.sh</code> <code>.bsah</code></li></ul>',15)]))}const m=e(o,[["render",t]]);export{_ as __pageData,m as default};
